const items = $input.all();
const thisWeek = items.slice(-5);
const actu = thisWeek.map(i => `- ${i.json.titre || i.json.title || 'Article sans titre'}`).join('\n');
const date = new Date();
const weekNum = Math.ceil(date.getDate() / 7);
return [{ json: { actusSemaine: actu, semaine: `S${weekNum}`, mois: date.toLocaleDateString('fr-FR', { month: 'long', year: 'numeric' }) } }];
